# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
import os
import sys

def get_mysql_connection():
    connection = mysql.connector.connect(
        host=input("Enter MySQL host (default: localhost): ").strip() or "localhost",
        user=input("Enter MySQL user: ").strip(),
        password=input("Enter MySQL password: ").strip(),
        database=input("Enter database name: ").strip(),
        allow_local_infile=True
    )
    return connection

def create_sample_table(cursor, table_name):
    cursor.execute(f"DROP TABLE IF EXISTS {table_name}")
    cursor.execute(f"""
        CREATE TABLE {table_name} (
            id INT,
            name VARCHAR(255),
            email VARCHAR(255),
            age INT,
            city VARCHAR(255)
        )
    """)
    print(f"Table '{table_name}' created successfully.")

def load_data_infile(cursor, file_path, table_name, field_separator=',', line_terminator='\\n', ignore_lines=1):
    if not os.path.exists(file_path):
        print(f"Error: File '{file_path}' does not exist.")
        return False
    
    abs_file_path = os.path.abspath(file_path)
    
    load_query = "LOAD DATA LOCAL INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY '{}' LINES TERMINATED BY '{}' IGNORE {} LINES".format(
        abs_file_path.replace('\\', '\\\\'),
        table_name,
        field_separator,
        line_terminator,
        ignore_lines
    )
    
    try:
        cursor.execute(load_query)
        print(f"Data loaded successfully from '{file_path}' into table '{table_name}'.")
        print(f"Rows affected: {cursor.rowcount}")
        return True
    except mysql.connector.Error as err:
        print(f"Error loading data: {err}")
        return False

def bulk_import_menu():
    print("\n" + "="*60)
    print("MySQL LOAD DATA INFILE - Bulk Import Tool")
    print("="*60)
    
    conn = None
    cursor = None
    
    try:
        conn = get_mysql_connection()
        cursor = conn.cursor()
        
        cursor.execute("SET GLOBAL local_infile = 1")
        print("\nConnected to MySQL successfully!")
        print("local_infile enabled.")
        
        while True:
            print("\n" + "-"*60)
            print("Options:")
            print("1. Create sample table")
            print("2. Load data from CSV file")
            print("3. Load data from TSV file")
            print("4. Load data with custom settings")
            print("5. View table data")
            print("6. Exit")
            print("-"*60)
            
            choice = input("\nEnter your choice (1-6): ").strip()
            
            if choice == '1':
                table_name = input("Enter table name to create: ").strip()
                if table_name:
                    create_sample_table(cursor, table_name)
                    conn.commit()
                    
            elif choice == '2':
                file_path = input("Enter CSV file path: ").strip()
                table_name = input("Enter target table name: ").strip()
                ignore_lines = input("Ignore header line? (y/n, default: y): ").strip().lower()
                ignore_count = 1 if ignore_lines != 'n' else 0
                
                if file_path and table_name:
                    if load_data_infile(cursor, file_path, table_name, ',', '\\n', ignore_count):
                        conn.commit()
                    else:
                        conn.rollback()
                        
            elif choice == '3':
                file_path = input("Enter TSV file path: ").strip()
                table_name = input("Enter target table name: ").strip()
                ignore_lines = input("Ignore header line? (y/n, default: y): ").strip().lower()
                ignore_count = 1 if ignore_lines != 'n' else 0
                
                if file_path and table_name:
                    if load_data_infile(cursor, file_path, table_name, '\\t', '\\n', ignore_count):
                        conn.commit()
                    else:
                        conn.rollback()
                        
            elif choice == '4':
                file_path = input("Enter file path: ").strip()
                table_name = input("Enter target table name: ").strip()
                field_separator = input("Enter field separator (default: ,): ").strip() or ','
                line_terminator = input("Enter line terminator (default: \\n): ").strip() or '\\n'
                ignore_lines = input("Number of lines to ignore (default: 1): ").strip() or '1'
                
                try:
                    ignore_count = int(ignore_lines)
                except ValueError:
                    ignore_count = 1
                
                if file_path and table_name:
                    if load_data_infile(cursor, file_path, table_name, field_separator, line_terminator, ignore_count):
                        conn.commit()
                    else:
                        conn.rollback()
                        
            elif choice == '5':
                table_name = input("Enter table name to view: ").strip()
                limit = input("Number of rows to display (default: 10): ").strip() or '10'
                
                try:
                    limit_count = int(limit)
                    cursor.execute(f"SELECT * FROM {table_name} LIMIT {limit_count}")
                    rows = cursor.fetchall()
                    
                    if rows:
                        columns = [desc[0] for desc in cursor.description]
                        print("\n" + " | ".join(columns))
                        print("-" * 60)
                        for row in rows:
                            print(" | ".join(str(val) for val in row))
                    else:
                        print("No data found in table.")
                        
                    cursor.execute(f"SELECT COUNT(*) FROM {table_name}")
                    total = cursor.fetchone()[0]
                    print(f"\nTotal rows in table: {total}")
                    
                except Exception as e:
                    print(f"Error viewing table: {e}")
                    
            elif choice == '6':
                print("\nExiting...")
                break
            else:
                print("Invalid choice. Please try again.")
                
    except mysql.connector.Error as err:
        print(f"MySQL Error: {err}")
    except Exception as e:
        print(f"Error: {e}")
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()
        print("Connection closed.")

if __name__ == "__main__":
    bulk_import_menu()